from pathlib import Path


class DataLoader:
    def __init__(self, path: str):
        self.path = Path(path)

    def load(self) -> list[dict]:
        results = []
        with open(self.path) as f:
            for line in f:
                line = line.strip()
                if line:
                    results.append({"raw": line})
        return results

    def validate(self, record: dict) -> bool:
        return bool(record.get("raw"))

