def find_duplicates(items: list[str]) -> list[str]:
    seen: dict[str, int] = {}
    dupes: list[str] = []
    for item in items:
        if item in seen:
            if seen[item] == 1:
                dupes.append(item)
            seen[item] += 1
        else:
            seen[item] = 1
    return dupes
